OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page



   LoadGroup("cursors1.grp");

   SetCursor (0);



   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=1;

   Group.HotSpot_Holder.DisableHotSpot(1);



   DisableScreen();

   Puzzle.OpenPuzzle(0);

   Puzzle.Mix(0,0,580,480);

   EnableScreen();

   ShowBuffer();

   Group.Sound_Holder.PlayDSound(9);

   FadeScreen(1,1000);



   int showBmp=0;

//   SetTimer(5000);

}





void OnLButtonDown(int x,int y)

{

        //Add your command handler code here

   SetTimer(0);

   Group.Sound_Holder.Stop(12);

}



void OnTimer(void)

{

        //Add your command handler code here

   SetTimer(0);

   Group.Sound_Holder.PlayDSound(12);

}







void OnClosePage(void)

{

	// Add your close page handler code here



}





void OnKeyDown(UINT nChar)

{

        //Add your command handler code here

   Puzzle.ShowFullBitmap(90,60,3);

}



